{
  "file": "backend/pipeline/nodes/json_response.py",
  "summary": "This file contains helper functions for parsing JSON responses from Claude, an AI model. It includes a function to extract plain text from structured content and another to parse the first complete JSON object or array from raw text, handling potential markdown code fences and malformed JSON.",
  "rules": [
    {
      "name": "extract_text",
      "description": "Converts Anthropic message content into plain text.",
      "conditions": ["content is a string"],
      "actions": ["return the string as-is"]
    },
    {
      "name": "extract_json",
      "description": "Extracts and parses the first complete JSON object or array from raw text, handling markdown code fences and malformed JSON.",
      "conditions": [
        "raw_text contains JSON-like content",
        "JSON is not well-formed"
      ],
      "actions": [
        "strip markdown code fences if present",
        "parse starting at the first '{' or '['",
        "use json_repair to fix malformed JSON"
      ]
    }
  ],
  "dependencies": ["json", "json_repair"]
}
